INSERT INTO `quizzes` (`id`, `assignment_id`, `question`, `opt_a`, `opt_b`, `opt_c`, `opt_d`, `answer`, `quiz_set_id`) VALUES
(25, 5, 'Cho h? m số y = x3 - 3x. Mệnh đề n? o sau đây l?  đúng?', 'H? m số đồng biến trên khoảng (-1; 1)', 'H? m số nghịch biến trên khoảng (-1; 1)', 'H? m số đồng biến trên khoảng (0; 2)', 'H? m số nghịch biến trên khoảng (1; +vô cùng)', 1, NULL),
(26, 5, 'Tìm giá trị cực đại của h? m số y = -x3 + 3x2 - 1.', 'y = -1', 'y = 1', 'y = 3', 'y = 0', 2, NULL),
