(175, NULL, 'Phủ định của mệnh đề: Tồn tại số nguyên n sao cho n chia hết cho 5 là mệnh đề nào?', 'Với mọi số nguyên n, n không chia hết cho 5.', 'Tồn tại số nguyên n sao cho n không chia hết cho 5.', 'Với mọi số nguyên n, n chia hết cho 5.', 'Không có số nguyên n nào chia hết cho 5.', 0, 5),
(176, NULL, 'Trong các mệnh đề sau, mệnh đề nào là mệnh đề chứa biến?', 'Số 9 là một số chính phương.', 'Hình bình hành có một góc vuông là hình chữ nhật.', 'Số nguyên n chia hết cho 3.', 'Một năm có 12 tháng.', 2, 5),
(177, NULL, 'Cho mệnh đề: Nếu một số tự nhiên có chữ số tận cùng là 0 thì số đó chia hết cho 5. Phát biểu nào sau đây diễn đạt mệnh đề trên dưới dạng điều kiện đủ?', 'Một số tự nhiên có chữ số tận cùng là 0 là điều kiện cần để số đó chia hết cho 5.', 'Một số tự nhiên có chữ số tận cùng là 0 là điều kiện đủ để số đó chia hết cho 5.', 'Một số tự nhiên chia hết cho 5 là điều kiện đủ để số đó có chữ số tận cùng là 0.', 'Để một số tự nhiên chia hết cho 5 thì điều kiện đủ là số đó phải có chữ số tận cùng là 0.', 1, 5),
(178, NULL, 'Cho mệnh đề: Một tam giác vuông khi và chỉ khi nó có một góc bằng 90 độ. Định lý này được phát biểu dưới dạng nào?', 'Mệnh đề kéo theo', 'Mệnh đề đảo', 'Mệnh đề phủ định', 'Mệnh đề tương đương hoặc điều kiện cần và đủ', 3, 5),
(179, NULL, 'Cho mệnh đề P: Tam giác ABC cân. Mệnh đề Q: Tam giác ABC đều. Mệnh đề nào sau đây là đúng?', 'P suy ra Q', 'Q suy ra P', 'P tương đương Q', 'Phủ định của P suy ra Q', 1, 5),
(180, NULL, 'Cho mệnh đề chứa biến P(n): n là số chẵn với n là số tự nhiên. Mệnh đề nào sau đây là một mệnh đề đúng?', 'P(1)', 'P(3)', 'P(5)', 'P(8)', 3, 5),
(181, NULL, 'Cho mệnh đề toán học: Tồn tại số thực x sao cho x bằng x bình phương. Giá trị nào của x chứng minh mệnh đề này đúng?', 'x = 2', 'x = -1', 'x = 1', 'x = 3', 2, 5),
(182, 6, 'Kết quả của phép tính 15 cộng 7 là bao nhiêu?', '21', '22', '23', '24', 1, NULL),
(183, 6, 'Tìm giá trị của x trong phương trình x trừ 5 bằng 10.', 'x = 5', 'x = -5', 'x = 15', 'x = 10', 2, NULL),
(184, 6, 'Một hình chữ nhật có chiều dài 8cm, chiều rộng 5cm. Diện tích của hình chữ nhật đó là bao nhiêu?', '13 cm2', '40 cm2', '26 cm2', '20 cm2', 1, NULL),
(185, 6, 'Số nào sau đây là số nguyên tố?', '4', '6', '9', '7', 3, NULL),
(186, 6, 'Trong các phân số sau, phân số nào bằng với phân số 2/4?', '1/2', '1/3', '1/4', '3/4', 0, NULL);
